/* ------------------------------------------------------------------ */
/* Stat chip definitions per view                                      */
/* ------------------------------------------------------------------ */

type StatView = "traditional" | "kanext";

interface StatChip {
  key: keyof Player;
  label: string;
  isPct?: boolean;
  isPrimary?: boolean;
  isInt?: boolean;
}

const TRADITIONAL_CHIPS: StatChip[] = [
  { key: "mpg", label: "MPG" },
  { key: "ppg", label: "PPG" },
  { key: "rpg", label: "RPG" },
  { key: "apg", label: "APG" },
  { key: "spg", label: "SPG" },
  { key: "bpg", label: "BPG" },
  { key: "topg", label: "TOPG" },
  { key: "pfpg", label: "PFPG" },
  { key: "gp", label: "GP", isInt: true },
];

const KANEXT_CHIPS: StatChip[] = [
  { key: "kr", label: "KR", isPrimary: true },
  { key: "krShooting", label: "SHT" },
  { key: "krFinishing", label: "FIN" },
  { key: "krPlaymaking", label: "PMK" },
  { key: "krPoaDefense", label: "POA" },
  { key: "krTeamDefense", label: "TDEF" },
  { key: "krRebounding", label: "REB" },
  { key: "krTools", label: "TOOLS" },
  { key: "krIq", label: "IQ" },
];

/* ------------------------------------------------------------------ */
/* Format helper                                                       */
/* ------------------------------------------------------------------ */

function fmtChip(val: unknown, isPct?: boolean, isInt?: boolean): string {
  if (val == null) return "\u2014";
  const n = Number(val);
  if (isNaN(n)) return "\u2014";
  if (isInt) return String(Math.round(n));
  return isPct ? `${n.toFixed(1)}%` : n.toFixed(1);
}

